     9→pub async fn cmd_logs(root: &Path, id: &str, follow: bool) -> anyhow::Result<()> {
    10→    use std::io::IsTerminal;
    11→    let card = paths::find_card(root, id).with_context(|| format!("card not found: {}", id))?;
    12→    let stdout_log = card.join("logs").join("stdout.log");
    13→    let stderr_log = card.join("logs").join("stderr.log");
    14→    let is_tty = std::io::stdout().is_terminal();
    15→
    16→    if !follow {
    17→        // Print all existing content once
    18→        print_log_section("stdout", &stdout_log, is_tty)?;
    19→        print_log_section("stderr", &stderr_log, is_tty)?;
    20→        return Ok(());
    21→    }
    22→
    23→    // --follow: open both files and stream new bytes as they arrive
    24→    let mut stdout_file = fs::File::open(&stdout_log)
    25→        .unwrap_or_else(|_| fs::File::open("/dev/null").expect("open /dev/null"));
    26→    let mut stderr_file = fs::File::open(&stderr_log)
    27→        .unwrap_or_else(|_| fs::File::open("/dev/null").expect("open /dev/null"));
    28→
    29→    // Drain any existing content first
    30→    let mut buf = Vec::new();
    31→    stdout_file.read_to_end(&mut buf)?;
    32→    if !buf.is_empty() {
    33→        print!("{}", colorize_chunk(&buf, is_tty));
    34→    }
    35→    let mut stdout_pos = stdout_file.stream_position()?;
    36→    buf.clear();
    37→
    38→    stderr_file.read_to_end(&mut buf)?;
    39→    if !buf.is_empty() {
    40→        eprint!("{}", colorize_chunk(&buf, is_tty));
    41→    }
    42→    let mut stderr_pos = stderr_file.stream_position()?;
    43→
    44→    loop {
    45→        tokio::time::sleep(Duration::from_millis(200)).await;
    46→
    47→        // Re-open if file was rotated/created after we started
    48→        if !stdout_log.exists() {
    49→            if let Ok(f) = fs::File::open(&stdout_log) {
    50→                stdout_file = f;
    51→                stdout_pos = 0;
    52→            }
    53→        }
    54→        if !stderr_log.exists() {
    55→            if let Ok(f) = fs::File::open(&stderr_log) {
    56→                stderr_file = f;
    57→                stderr_pos = 0;
    58→            }
    59→        }
    60→
    61→        // Read any new bytes from stdout
    62→        stdout_file.seek(SeekFrom::Start(stdout_pos))?;
    63→        buf.clear();
    64→        stdout_file.read_to_end(&mut buf)?;
    65→        if !buf.is_empty() {
    66→            print!("{}", colorize_chunk(&buf, is_tty));
    67→            std::io::stdout().flush()?;
    68→            stdout_pos += buf.len() as u64;
    69→        }
    70→
    71→        // Read any new bytes from stderr
    72→        stderr_file.seek(SeekFrom::Start(stderr_pos))?;
    73→        buf.clear();
    74→        stderr_file.read_to_end(&mut buf)?;
    75→        if !buf.is_empty() {
    76→            eprint!("{}", colorize_chunk(&buf, is_tty));
    77→            std::io::stderr().flush()?;
    78→            stderr_pos += buf.len() as u64;
    79→        }
    80→
    81→        // Stop following once the card leaves running/
    82→        let still_running = paths::find_card_in_state(root, id, "running");
    83→        if !still_running {
    84→            break;
    85→        }
    86→    }
    87→
    88→    Ok(())
    89→}
